-- ============================================================
-- CNE Colombia · Conversación Nacional (multiplataforma por departamento)
-- Tabla análoga a content_manager_mapa_countries pero a nivel departamental,
-- con volúmenes por plataforma (TikTok, X, Instagram, Facebook).
-- Los valores de "nombre" coinciden (tras normalizar acentos/mayúsculas) con
-- la propiedad NOMBRE_DPT del GeoJSON public/colombia-departamentos.geojson.
-- Pantalla: /nacional (modo CNE).
-- ============================================================

CREATE TABLE IF NOT EXISTS content_manager_nacional_departamentos (
    id                   TEXT PRIMARY KEY,        -- Código DANE del departamento
    nombre               TEXT NOT NULL,           -- Nombre (match con NOMBRE_DPT del GeoJSON)
    capital              TEXT,
    lat                  NUMERIC,
    lng                  NUMERIC,
    tema                 TEXT,
    keywords             JSONB DEFAULT '[]'::jsonb,
    sentimiento          TEXT,
    sentimiento_pct      JSONB,                   -- {positivo, neutral, negativo}
    volumen              NUMERIC DEFAULT 0,       -- Menciones totales (suma de plataformas)
    plataforma_dominante TEXT,
    plataformas          JSONB,                   -- {"TikTok": n, "X": n, "Instagram": n, "Facebook": n}
    resumen              TEXT,
    tendencia            TEXT,                    -- 'sube' | 'estable' | 'baja'
    pct_cambio           NUMERIC DEFAULT 0,
    top_hashtags         JSONB DEFAULT '[]'::jsonb,
    update_time          TEXT
);

-- ---------- Seguridad (RLS) coherente con el resto del proyecto ----------
ALTER TABLE content_manager_nacional_departamentos ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Lectura abierta para autenticados" ON content_manager_nacional_departamentos;
CREATE POLICY "Lectura abierta para autenticados"
    ON content_manager_nacional_departamentos FOR SELECT TO authenticated USING (true);

DROP POLICY IF EXISTS "Escritura solo para admins" ON content_manager_nacional_departamentos;
CREATE POLICY "Escritura solo para admins"
    ON content_manager_nacional_departamentos FOR ALL TO authenticated
    USING (public.is_admin()) WITH CHECK (public.is_admin());

