-- ---------- Realtime: actualización automática del mapa ----------
-- Habilita la replicación para que /nacional se refresque en vivo al entrar datos.
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_publication_tables
        WHERE pubname = 'supabase_realtime' AND schemaname = 'public'
          AND tablename = 'content_manager_nacional_departamentos'
    ) THEN
        ALTER PUBLICATION supabase_realtime ADD TABLE public.content_manager_nacional_departamentos;
    END IF;
END $$;
